INDEX_HTML = '<!doctype html>\n<html lang="en">\n<head>\n  <meta charset="utf-8" />\n  <meta\n    http-equiv="Content-Security-Policy"\n    content="default-src \'self\'; connect-src \'self\' http://127.0.0.1:8844; img-src \'self\' data: file:; style-src \'self\' \'unsafe-inline\'; script-src \'self\';"\n  />\n  <meta name="viewport" content="width=device-width, initial-scale=1" />\n  <title>KayocktheOS Bridge</title>\n  <link rel="stylesheet" href="style.css" />\n</head>\n<body>\n  <div id="bootScreen" class="bootScreen">\n    <div class="bootCard">\n      <div class="sigil large">K</div>\n      <h1>Opening the Workshop...</h1>\n      <p id="bootLine">Preparing the Bridge.</p>\n      <div class="bootBar"><span id="bootProgress"></span></div>\n    </div>\n  </div>\n\n  <div class="app">\n    <aside class="sidebar">\n      <div class="brand">\n        <div class="sigil">K</div>\n        <div>\n          <h1>KayocktheOS</h1>\n          <p>Living Knowledge Workshop</p>\n        </div>\n      </div>\n\n      <nav>\n        <button class="nav active" data-room="home">🏠 Home</button>\n        <button class="nav" data-room="academy">🎓 Academy</button>\n        <button class="nav" data-room="workshop">🔧 Workshop</button>\n        <button class="nav" data-room="library">📚 Library</button>\n        <button class="nav" data-room="observatory">🔍 Observatory</button>\n        <button class="nav" data-room="foundry">🏛 Foundry</button>\n      </nav>\n\n      <div class="sidebarStatus">\n        <div><span id="apiDot" class="dot wait"></span> Core API</div>\n        <div><span id="runtimeDot" class="dot wait"></span> Runtime</div>\n        <div><span id="foxaiDot" class="dot wait"></span> FOXAI</div>\n      </div>\n    </aside>\n\n    <main class="main">\n      <header class="topbar">\n        <div>\n          <p class="eyebrow">Bridge OS</p>\n          <h2 id="roomTitle">Home</h2>\n        </div>\n        <div class="topRight">\n          <button id="bellBtn" class="bell">🔔 <span id="bellCount">0</span></button>\n          <div class="operator">\n            <span id="operatorName">Operator</span>\n            <small id="versionLabel">Loading...</small>\n          </div>\n        </div>\n      </header>\n\n      <div id="bellPanel" class="bellPanel hidden">\n        <h4>Workshop Bell</h4>\n        <div id="notificationList" class="smallList"></div>\n      </div>\n\n      <section id="home" class="room active">\n        <div class="hero">\n          <div>\n            <p class="eyebrow">Welcome back</p>\n            <h3 id="heroGreeting">Opening the Workshop...</h3>\n            <p id="academyGreeting">The Academy is open. Today\'s lesson awaits.</p>\n          </div>\n          <div id="overallStatus" class="statusPill wait">Checking</div>\n        </div>\n\n        <div class="missionCard">\n          <div>\n            <p class="eyebrow">Today\'s Mission</p>\n            <h4 id="missionTitle">Continue building the Bridge</h4>\n            <p id="missionDetail">Bring the rooms to life with live capability cards and professor studies.</p>\n          </div>\n          <button class="primaryBtn" data-room-jump="workshop">Continue</button>\n        </div>\n\n        <div class="grid three">\n          <article class="card">\n            <h4>System Health</h4>\n            <div id="healthList" class="list smallList"></div>\n          </article>\n          <article class="card">\n            <h4>FOXAI Capabilities</h4>\n            <div id="homeCapabilityMini" class="capMini"></div>\n          </article>\n          <article class="card">\n            <h4>Local Chat</h4>\n            <div id="chatSummary" class="smallList"></div>\n          </article>\n        </div>\n\n        <article class="card chatCard">\n          <h4>Ask the Academy</h4>\n          <div id="chatLog" class="chatLog">\n            <div class="message system">Local chat is ready when the model runtime is online.</div>\n          </div>\n          <form id="chatForm" class="chatForm">\n            <input id="chatInput" placeholder="Ask the Academy..." />\n            <button type="submit">Ask</button>\n          </form>\n        </article>\n      </section>\n\n      <section id="academy" class="room">\n        <article class="card wide">\n          <div class="sectionHeader">\n            <div>\n              <p class="eyebrow">Academy</p>\n              <h4>Hall of Professors</h4>\n            </div>\n            <span id="professorCount" class="badge">-- professors</span>\n          </div>\n          <div id="professorGrid" class="professorGrid"></div>\n        </article>\n      </section>\n\n      <section id="workshop" class="room">\n        <div class="grid two">\n          <article class="card wide">\n            <div class="sectionHeader">\n              <div>\n                <p class="eyebrow">Discovered, never hardcoded</p>\n                <h4>Capability Cards</h4>\n              </div>\n              <span id="capabilityCount" class="badge">-- available</span>\n            </div>\n            <div id="capabilityCards" class="capabilityCards"></div>\n          </article>\n        </div>\n      </section>\n\n      <section id="library" class="room">\n        <article class="card">\n          <h4>Iron Library</h4>\n          <p>Books, manuals, comics, notes, and documents will be indexed here.</p>\n          <div id="librarySummary" class="smallList"></div>\n        </article>\n      </section>\n\n      <section id="observatory" class="room">\n        <div class="grid two">\n          <article class="card">\n            <h4>Host Computer</h4>\n            <div id="systemSummary" class="smallList"></div>\n          </article>\n          <article class="card">\n            <h4>Events</h4>\n            <div id="eventList" class="smallList"></div>\n          </article>\n        </div>\n      </section>\n\n      <section id="foundry" class="room">\n        <div class="grid two">\n          <article class="card">\n            <h4>Release Readiness</h4>\n            <div id="releaseSummary" class="smallList"></div>\n          </article>\n          <article class="card">\n            <h4>Workshop Wall</h4>\n            <div id="workshopWall" class="smallList"></div>\n          </article>\n        </div>\n      </section>\n    </main>\n  </div>\n\n  <script src="renderer.js"></script>\n</body>\n</html>\n'
STYLE_CSS = ':root {\n  color-scheme: dark;\n  --bg: #050805;\n  --panel: #0d1a0d;\n  --panel2: #122412;\n  --text: #ddffdf;\n  --muted: #95d795;\n  --accent: #00ff66;\n  --warn: #ffd166;\n  --bad: #ff5c5c;\n  --border: rgba(0,255,102,.22);\n}\n\n* { box-sizing: border-box; }\n\nbody {\n  margin: 0;\n  background: radial-gradient(circle at top, #123312, var(--bg) 55%);\n  color: var(--text);\n  font-family: "Segoe UI", Arial, sans-serif;\n}\n\n.bootScreen {\n  position: fixed;\n  inset: 0;\n  background: radial-gradient(circle at top, #123312, #020402 70%);\n  display: grid;\n  place-items: center;\n  z-index: 99;\n  transition: opacity .45s ease, visibility .45s ease;\n}\n\n.bootScreen.hidden {\n  opacity: 0;\n  visibility: hidden;\n}\n\n.bootCard {\n  width: min(520px, 90vw);\n  border: 1px solid var(--border);\n  border-radius: 28px;\n  padding: 34px;\n  background: rgba(6,16,6,.86);\n  text-align: center;\n  box-shadow: 0 0 60px rgba(0,255,102,.12);\n}\n\n.sigil.large {\n  width: 72px;\n  height: 72px;\n  font-size: 36px;\n  margin: 0 auto 18px;\n}\n\n.bootCard h1 { margin: 0 0 10px; }\n.bootCard p { color: var(--muted); }\n\n.bootBar {\n  height: 10px;\n  border-radius: 999px;\n  background: rgba(255,255,255,.08);\n  overflow: hidden;\n  margin-top: 18px;\n}\n\n.bootBar span {\n  display: block;\n  height: 100%;\n  width: 8%;\n  background: var(--accent);\n  box-shadow: 0 0 20px var(--accent);\n  transition: width .5s ease;\n}\n\n.app {\n  display: grid;\n  grid-template-columns: 280px 1fr;\n  min-height: 100vh;\n}\n\n.sidebar {\n  border-right: 1px solid var(--border);\n  background: rgba(5,12,5,.88);\n  padding: 22px;\n  display: flex;\n  flex-direction: column;\n  gap: 22px;\n}\n\n.brand {\n  display: flex;\n  gap: 14px;\n  align-items: center;\n}\n\n.sigil {\n  width: 48px;\n  height: 48px;\n  border: 1px solid var(--accent);\n  border-radius: 14px;\n  display: grid;\n  place-items: center;\n  color: var(--accent);\n  font-weight: 900;\n  font-size: 24px;\n  box-shadow: 0 0 24px rgba(0,255,102,.12);\n}\n\n.brand h1 { margin: 0; font-size: 20px; }\n.brand p { margin: 3px 0 0; color: var(--muted); font-size: 12px; }\n\nnav { display: grid; gap: 8px; }\n\n.nav {\n  background: transparent;\n  color: var(--text);\n  border: 1px solid rgba(149,215,149,.14);\n  border-radius: 12px;\n  padding: 12px;\n  text-align: left;\n  cursor: pointer;\n  font-size: 15px;\n}\n\n.nav:hover, .nav.active {\n  border-color: var(--accent);\n  background: rgba(0,255,102,.08);\n}\n\n.sidebarStatus {\n  margin-top: auto;\n  display: grid;\n  gap: 10px;\n  color: var(--muted);\n  font-size: 14px;\n}\n\n.dot {\n  display: inline-block;\n  width: 10px;\n  height: 10px;\n  border-radius: 99px;\n  margin-right: 8px;\n}\n.dot.ok { background: var(--accent); box-shadow: 0 0 8px var(--accent); }\n.dot.wait { background: var(--warn); box-shadow: 0 0 8px var(--warn); }\n.dot.bad { background: var(--bad); box-shadow: 0 0 8px var(--bad); }\n\n.main {\n  padding: 24px;\n  overflow: auto;\n  position: relative;\n}\n\n.topbar {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  margin-bottom: 22px;\n}\n\n.topRight {\n  display: flex;\n  gap: 14px;\n  align-items: center;\n}\n\n.bell {\n  background: rgba(0,255,102,.08);\n  border: 1px solid rgba(0,255,102,.24);\n  color: var(--text);\n  border-radius: 999px;\n  padding: 10px 14px;\n  cursor: pointer;\n}\n\n.bell span {\n  color: var(--accent);\n  font-weight: 900;\n}\n\n.bellPanel {\n  position: absolute;\n  top: 78px;\n  right: 24px;\n  width: 360px;\n  max-height: 450px;\n  overflow: auto;\n  background: rgba(6,16,6,.96);\n  border: 1px solid var(--border);\n  border-radius: 18px;\n  padding: 16px;\n  z-index: 20;\n  box-shadow: 0 18px 50px rgba(0,0,0,.36);\n}\n.bellPanel.hidden { display: none; }\n.bellPanel h4 { margin: 0 0 12px; color: var(--accent); }\n\n.eyebrow {\n  text-transform: uppercase;\n  letter-spacing: .14em;\n  color: var(--muted);\n  font-size: 12px;\n  margin: 0 0 4px;\n}\n\n.topbar h2 {\n  margin: 0;\n  font-size: 36px;\n}\n\n.operator {\n  text-align: right;\n  color: var(--accent);\n}\n.operator small {\n  display: block;\n  color: var(--muted);\n}\n\n.room { display: none; }\n.room.active { display: block; }\n\n.hero {\n  border: 1px solid var(--border);\n  border-radius: 24px;\n  padding: 28px;\n  background: linear-gradient(135deg, rgba(18,36,18,.95), rgba(5,10,5,.92));\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  margin-bottom: 18px;\n}\n\n.hero h3 {\n  font-size: 42px;\n  margin: 8px 0;\n}\n\n.statusPill {\n  border: 1px solid var(--warn);\n  color: var(--warn);\n  border-radius: 999px;\n  padding: 12px 18px;\n  font-weight: 900;\n}\n.statusPill.ok { color: var(--accent); border-color: var(--accent); }\n.statusPill.bad { color: var(--bad); border-color: var(--bad); }\n\n.missionCard {\n  display: flex;\n  justify-content: space-between;\n  gap: 18px;\n  align-items: center;\n  border: 1px solid rgba(149,215,149,.16);\n  border-radius: 18px;\n  padding: 20px;\n  background: rgba(13,26,13,.7);\n  margin-bottom: 18px;\n}\n\n.missionCard h4 { margin: 4px 0 6px; font-size: 24px; }\n.missionCard p { margin: 0; color: var(--muted); }\n\n.primaryBtn {\n  border: 1px solid var(--accent);\n  border-radius: 12px;\n  background: rgba(0,255,102,.12);\n  color: var(--accent);\n  padding: 13px 18px;\n  cursor: pointer;\n  font-weight: 900;\n}\n\n.grid { display: grid; gap: 18px; }\n.grid.two { grid-template-columns: repeat(2, minmax(280px, 1fr)); }\n.grid.three { grid-template-columns: repeat(3, minmax(220px, 1fr)); }\n\n.card {\n  background: rgba(13,26,13,.86);\n  border: 1px solid rgba(149,215,149,.16);\n  border-radius: 18px;\n  padding: 20px;\n}\n\n.card h4 {\n  margin: 0 0 14px;\n  color: var(--accent);\n  font-size: 20px;\n}\n\n.wide { grid-column: 1 / -1; }\n\n.sectionHeader {\n  display: flex;\n  justify-content: space-between;\n  gap: 16px;\n  align-items: center;\n  margin-bottom: 14px;\n}\n.sectionHeader h4 { margin: 0; }\n\n.badge {\n  border: 1px solid rgba(0,255,102,.28);\n  border-radius: 999px;\n  color: var(--accent);\n  padding: 8px 12px;\n  font-weight: 800;\n}\n\n.list, .smallList { display: grid; gap: 8px; }\n\n.item {\n  padding: 9px 10px;\n  border-radius: 10px;\n  background: rgba(0,0,0,.22);\n  border-left: 4px solid var(--warn);\n}\n\n.item.ok { border-left-color: var(--accent); }\n.item.bad { border-left-color: var(--bad); }\n\n.item strong { display: block; }\n.item span { color: var(--muted); font-size: 13px; }\n\n.capMini {\n  display: grid;\n  gap: 10px;\n}\n\n.capLine {\n  display: grid;\n  grid-template-columns: 140px 1fr 34px;\n  gap: 10px;\n  align-items: center;\n}\n.capBar {\n  height: 8px;\n  border-radius: 999px;\n  background: rgba(255,255,255,.08);\n  overflow: hidden;\n}\n.capBar span {\n  display: block;\n  height: 100%;\n  background: var(--accent);\n  min-width: 2px;\n}\n\n.capabilityCards {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));\n  gap: 14px;\n}\n.capabilityCard {\n  background: rgba(0,0,0,.2);\n  border: 1px solid rgba(149,215,149,.14);\n  border-radius: 16px;\n  padding: 16px;\n}\n.capabilityCard .icon { font-size: 30px; }\n.capabilityCard h5 { margin: 10px 0 6px; color: var(--accent); font-size: 19px; }\n.capabilityCard p { color: var(--muted); }\n.capabilityCard .score { color: var(--warn); font-weight: 900; }\n\n.professorGrid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));\n  gap: 14px;\n}\n.professor {\n  background: rgba(0,0,0,.18);\n  border: 1px solid rgba(149,215,149,.14);\n  border-radius: 14px;\n  padding: 16px;\n  transition: transform .2s ease, border-color .2s ease;\n}\n.professor:hover {\n  transform: translateY(-2px);\n  border-color: rgba(0,255,102,.45);\n}\n.professor h5 { margin: 0 0 8px; font-size: 17px; color: var(--accent); }\n.professor p { color: var(--muted); }\n\n.chatCard { margin-top: 18px; }\n\n.chatLog {\n  height: 230px;\n  overflow: auto;\n  display: grid;\n  gap: 10px;\n  align-content: start;\n  padding: 12px;\n  background: rgba(0,0,0,.22);\n  border-radius: 14px;\n  margin-bottom: 12px;\n}\n\n.message {\n  padding: 10px 12px;\n  border-radius: 12px;\n  background: rgba(255,255,255,.06);\n}\n.message.user { border-left: 4px solid var(--warn); }\n.message.assistant { border-left: 4px solid var(--accent); }\n.message.system { border-left: 4px solid var(--muted); color: var(--muted); }\n\n.chatForm {\n  display: grid;\n  grid-template-columns: 1fr 110px;\n  gap: 10px;\n}\n\n.chatForm input {\n  background: rgba(0,0,0,.35);\n  color: var(--text);\n  border: 1px solid rgba(149,215,149,.2);\n  border-radius: 12px;\n  padding: 13px;\n}\n\n.chatForm button {\n  background: rgba(0,255,102,.14);\n  color: var(--accent);\n  border: 1px solid var(--accent);\n  border-radius: 12px;\n  cursor: pointer;\n  font-weight: 800;\n}\n\n@media (max-width: 980px) {\n  .app { grid-template-columns: 1fr; }\n  .sidebar { position: relative; }\n  .grid.two, .grid.three { grid-template-columns: 1fr; }\n}\n'
RENDERER_JS = 'const API = window.kayockBridge?.apiBase || \'http://127.0.0.1:8844\';\n\nconst state = {\n  status: null,\n  academy: null,\n  foxai: null,\n  runtime: null,\n  localChat: null,\n  release: null,\n  bridge: null,\n  notifications: []\n};\n\nfunction $(id) { return document.getElementById(id); }\n\nfunction setBoot(line, progress) {\n  const bootLine = $(\'bootLine\');\n  const bootProgress = $(\'bootProgress\');\n  if (bootLine) bootLine.textContent = line;\n  if (bootProgress) bootProgress.style.width = `${progress}%`;\n}\n\nfunction hideBoot() {\n  setTimeout(() => $(\'bootScreen\')?.classList.add(\'hidden\'), 650);\n}\n\nfunction setDot(id, status, waiting=false) {\n  const el = $(id);\n  if (!el) return;\n  el.className = \'dot \' + (waiting ? \'wait\' : (status ? \'ok\' : \'bad\'));\n}\n\nfunction item(label, value, status = \'wait\') {\n  return `<div class="item ${status}"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(value ?? \'\')}</span></div>`;\n}\n\nfunction escapeHtml(value) {\n  return String(value ?? \'\').replace(/[&<>"\']/g, ch => ({\n    \'&\': \'&amp;\', \'<\': \'&lt;\', \'>\': \'&gt;\', \'"\': \'&quot;\', "\'": \'&#39;\'\n  }[ch]));\n}\n\nasync function fetchJson(path) {\n  const res = await fetch(API + path, { cache: \'no-store\' });\n  if (!res.ok) throw new Error(`${path} ${res.status}`);\n  return await res.json();\n}\n\nasync function refresh() {\n  try {\n    setBoot(\'Checking Core API...\', 20);\n    const [status, academy, foxai, runtime, localChat, release, bridge] = await Promise.allSettled([\n      fetchJson(\'/api/status\'),\n      fetchJson(\'/api/academy\'),\n      fetchJson(\'/api/foxai\'),\n      fetchJson(\'/api/runtime\'),\n      fetchJson(\'/api/local-chat\'),\n      fetchJson(\'/api/release-check\'),\n      fetchJson(\'/api/bridge\')\n    ]);\n\n    setBoot(\'Greeting the professors...\', 45);\n    state.status = status.status === \'fulfilled\' ? status.value : null;\n    state.academy = academy.status === \'fulfilled\' ? academy.value : null;\n    state.foxai = foxai.status === \'fulfilled\' ? foxai.value : null;\n    state.runtime = runtime.status === \'fulfilled\' ? runtime.value : null;\n    state.localChat = localChat.status === \'fulfilled\' ? localChat.value : null;\n    state.release = release.status === \'fulfilled\' ? release.value : null;\n    state.bridge = bridge.status === \'fulfilled\' ? bridge.value : null;\n\n    setBoot(\'Scanning FOXAI capabilities...\', 70);\n    buildNotifications();\n    render();\n\n    setBoot(\'The Academy is open.\', 100);\n    hideBoot();\n  } catch (err) {\n    setDot(\'apiDot\', false);\n    $(\'overallStatus\').textContent = \'Core Offline\';\n    $(\'overallStatus\').className = \'statusPill bad\';\n    notify(\'Core API\', \'The Core API is offline. Start KayocktheOS first.\', \'bad\');\n    renderNotifications();\n    setBoot(\'Core API offline.\', 100);\n    hideBoot();\n  }\n}\n\nfunction notify(title, message, status=\'ok\') {\n  const key = `${title}:${message}`;\n  if (state.notifications.some(n => n.key === key)) return;\n  state.notifications.unshift({\n    key,\n    title,\n    message,\n    status,\n    time: new Date().toLocaleTimeString()\n  });\n  state.notifications = state.notifications.slice(0, 20);\n}\n\nfunction buildNotifications() {\n  if (state.foxai?.exists) {\n    const s = state.foxai.summary || {};\n    notify(\'FOXAI\', `${s.total_assets || 0} asset(s) discovered in the AI warehouse.`, \'ok\');\n    if ((s.llm_models || 0) > 0) notify(\'Academy\', `${s.llm_models} chat model(s) available for professor teams.`, \'ok\');\n    if ((s.image_models || 0) > 0) notify(\'Creative Studio\', `${s.image_models} image model(s) discovered.`, \'ok\');\n  } else {\n    notify(\'FOXAI\', \'FOXAI repository not detected at Z:\\\\FOXAI.\', \'bad\');\n  }\n\n  if (state.runtime?.online) {\n    notify(\'Local Runtime\', \'A local model runtime is online.\', \'ok\');\n  } else {\n    notify(\'Local Runtime\', \'Runtime is offline. Launch the selected model runtime to enable chat.\', \'wait\');\n  }\n}\n\nfunction render() {\n  const apiOnline = !!state.status;\n  setDot(\'apiDot\', apiOnline);\n  setDot(\'runtimeDot\', !!state.runtime?.online);\n  setDot(\'foxaiDot\', !!state.foxai?.exists);\n\n  const project = state.status?.project || {};\n  const operator = state.status?.operator || {};\n  $(\'operatorName\').textContent = operator.display_name || \'Operator\';\n  $(\'versionLabel\').textContent = `${project.name || \'KayocktheOS\'} ${project.version || \'\'}`;\n  $(\'heroGreeting\').textContent = `Good day, ${operator.display_name || \'Operator\'}.`;\n  $(\'academyGreeting\').textContent = state.academy?.startup_greeting || \'The Academy is open. Today’s lesson awaits.\';\n\n  const good = apiOnline && state.foxai?.exists;\n  $(\'overallStatus\').textContent = good ? \'Workshop Online\' : \'Needs Attention\';\n  $(\'overallStatus\').className = \'statusPill \' + (good ? \'ok\' : \'wait\');\n\n  renderHealth();\n  renderHomeCapabilities();\n  renderChatSummary();\n  renderAcademy();\n  renderCapabilities();\n  renderSystem();\n  renderEvents();\n  renderRelease();\n  renderWorkshopWall();\n  renderLibrary();\n  renderNotifications();\n}\n\nfunction renderHealth() {\n  const health = state.status?.health || [];\n  $(\'healthList\').innerHTML = health.slice(0, 8).map(h =>\n    item(h.label, `${h.status} — ${h.path}`, h.status === \'OK\' ? \'ok\' : \'bad\')\n  ).join(\'\') || item(\'Core API\', \'No data yet\', \'bad\');\n}\n\nfunction capabilityData() {\n  const llms = state.foxai?.assets?.llms || [];\n  const images = state.foxai?.assets?.image_models || [];\n  const workflows = state.foxai?.assets?.workflows || [];\n  const count = key => llms.filter(m => (m.capabilities || []).includes(key)).length;\n\n  return [\n    { icon: \'🧠\', label: \'Conversation\', value: llms.length, detail: \'Ask and reason with local models.\' },\n    { icon: \'💻\', label: \'Programming\', value: count(\'coding\'), detail: \'Code help and review.\' },\n    { icon: \'🧪\', label: \'Reasoning\', value: count(\'reasoning\'), detail: \'Logic, planning, and analysis.\' },\n    { icon: \'👁\', label: \'Vision\', value: count(\'vision\'), detail: \'Image understanding models.\' },\n    { icon: \'🎨\', label: \'Image Creation\', value: images.length, detail: \'ComfyUI checkpoints.\' },\n    { icon: \'🧩\', label: \'Workflows\', value: workflows.length, detail: \'ComfyUI workflow files.\' }\n  ];\n}\n\nfunction renderHomeCapabilities() {\n  const max = Math.max(1, ...capabilityData().map(c => c.value));\n  $(\'homeCapabilityMini\').innerHTML = capabilityData().slice(0, 5).map(c => `\n    <div class="capLine">\n      <span>${c.icon} ${escapeHtml(c.label)}</span>\n      <div class="capBar"><span style="width:${Math.max(4, (c.value / max) * 100)}%"></span></div>\n      <strong>${c.value}</strong>\n    </div>\n  `).join(\'\');\n}\n\nfunction renderCapabilities() {\n  const caps = capabilityData();\n  $(\'capabilityCount\').textContent = `${caps.filter(c => c.value > 0).length} available`;\n  $(\'capabilityCards\').innerHTML = caps.map(c => `\n    <div class="capabilityCard">\n      <div class="icon">${c.icon}</div>\n      <h5>${escapeHtml(c.label)}</h5>\n      <p>${escapeHtml(c.detail)}</p>\n      <div class="score">${c.value ? c.value + \' available\' : \'Not available yet\'}</div>\n    </div>\n  `).join(\'\');\n}\n\nfunction renderChatSummary() {\n  const rt = state.runtime || {};\n  const lc = state.localChat || {};\n  $(\'chatSummary\').innerHTML = [\n    item(\'Runtime\', rt.online ? \'Online\' : \'Offline\', rt.online ? \'ok\' : \'bad\'),\n    item(\'Selected Model\', lc.selected_model || \'Not selected\', lc.selected_model ? \'ok\' : \'wait\'),\n    item(\'Launch Helper\', lc.launch_helper || \'Missing\', lc.launch_helper ? \'ok\' : \'wait\')\n  ].join(\'\');\n}\n\nfunction renderAcademy() {\n  const colleges = state.academy?.colleges || [];\n  $(\'professorCount\').textContent = `${colleges.length} professors`;\n  $(\'professorGrid\').innerHTML = colleges.map(c => `\n    <div class="professor">\n      <h5>${escapeHtml(c.professor || c.name)}</h5>\n      <p><strong>${escapeHtml(c.name)}</strong></p>\n      <p>“${escapeHtml(c.motto || \'\')}”</p>\n      <p>${escapeHtml((c.domains || []).join(\' · \'))}</p>\n    </div>\n  `).join(\'\') || \'<p>No Academy data yet.</p>\';\n}\n\nfunction renderSystem() {\n  const sys = state.status?.system || {};\n  const cpu = sys.cpu || {};\n  const mem = sys.memory || {};\n  const disk = sys.disk || {};\n  $(\'systemSummary\').innerHTML = [\n    item(\'OS\', sys.os?.platform || \'Unknown\', sys.os ? \'ok\' : \'wait\'),\n    item(\'CPU\', cpu.name || \'Unknown\', cpu.name ? \'ok\' : \'wait\'),\n    item(\'RAM\', mem.total_gb ? `${mem.total_gb} GB` : \'Unknown\', mem.total_gb ? \'ok\' : \'wait\'),\n    item(\'Disk Free\', disk.free_gb ? `${disk.free_gb} GB free` : \'Unknown\', disk.free_gb ? \'ok\' : \'wait\')\n  ].join(\'\');\n}\n\nfunction renderEvents() {\n  const events = state.status?.events || state.bridge?.events || [];\n  $(\'eventList\').innerHTML = events.slice(-8).reverse().map(e =>\n    item(e.type || \'event\', e.message || e.timestamp || \'\', \'ok\')\n  ).join(\'\') || item(\'Events\', \'No events yet\', \'wait\');\n}\n\nfunction renderRelease() {\n  const r = state.release || {};\n  $(\'releaseSummary\').innerHTML = [\n    item(\'Ship Ready\', r.ship_ready ? \'YES\' : \'NO / Unknown\', r.ship_ready ? \'ok\' : \'wait\'),\n    item(\'Version\', r.version || \'Unknown\', r.version ? \'ok\' : \'wait\'),\n    item(\'Warnings\', r.summary?.warnings ?? \'Unknown\', \'wait\')\n  ].join(\'\');\n}\n\nfunction renderWorkshopWall() {\n  $(\'workshopWall\').innerHTML = [\n    item(\'Architecture Law #1\', \'Build complete, integrated features—not isolated components.\', \'ok\'),\n    item(\'Architecture Law #2\', \'Capabilities are discovered, never hardcoded.\', \'ok\'),\n    item(\'Architecture Law #3\', \'The interface teaches, assists, and builds.\', \'ok\'),\n    item(\'Feature 002\', \'Bridge rooms are now visible.\', \'ok\'),\n    item(\'Feature 001\', \'Local Chat in progress.\', \'wait\')\n  ].join(\'\');\n}\n\nfunction renderLibrary() {\n  const files = state.status?.system?.assets?.knowledge_files;\n  $(\'librarySummary\').innerHTML = [\n    item(\'Knowledge Files\', files ?? \'Unknown\', files ? \'ok\' : \'wait\'),\n    item(\'Next\', \'Iron Library indexing is a future complete feature.\', \'wait\')\n  ].join(\'\');\n}\n\nfunction renderNotifications() {\n  $(\'bellCount\').textContent = state.notifications.length;\n  $(\'notificationList\').innerHTML = state.notifications.map(n =>\n    item(n.title, `${n.message} — ${n.time}`, n.status === \'bad\' ? \'bad\' : (n.status === \'wait\' ? \'wait\' : \'ok\'))\n  ).join(\'\') || item(\'Workshop Bell\', \'No notifications yet.\', \'wait\');\n}\n\nasync function sendChat(prompt) {\n  addMessage(\'user\', prompt);\n  addMessage(\'system\', \'Sending to local AI Gateway...\');\n  try {\n    const res = await fetch(API + \'/api/chat\', {\n      method: \'POST\',\n      headers: { \'Content-Type\': \'application/json\' },\n      body: JSON.stringify({ prompt })\n    });\n    const data = await res.json();\n    const text = data.response || data.message || data.error || JSON.stringify(data).slice(0, 1000);\n    addMessage(data.ok ? \'assistant\' : \'system\', text);\n  } catch (err) {\n    addMessage(\'system\', \'Chat failed: \' + err.message);\n  }\n}\n\nfunction addMessage(role, text) {\n  const log = $(\'chatLog\');\n  const div = document.createElement(\'div\');\n  div.className = \'message \' + role;\n  div.textContent = text;\n  log.appendChild(div);\n  log.scrollTop = log.scrollHeight;\n}\n\nfunction openRoom(room) {\n  document.querySelectorAll(\'.nav\').forEach(b => b.classList.toggle(\'active\', b.dataset.room === room));\n  document.querySelectorAll(\'.room\').forEach(r => r.classList.remove(\'active\'));\n  document.getElementById(room)?.classList.add(\'active\');\n  const btn = document.querySelector(`.nav[data-room="${room}"]`);\n  if (btn) $(\'roomTitle\').textContent = btn.textContent.replace(/[^\\w\\s]/g, \'\').trim();\n}\n\ndocument.querySelectorAll(\'.nav\').forEach(btn => {\n  btn.addEventListener(\'click\', () => openRoom(btn.dataset.room));\n});\n\ndocument.querySelectorAll(\'[data-room-jump]\').forEach(btn => {\n  btn.addEventListener(\'click\', () => openRoom(btn.dataset.roomJump));\n});\n\n$(\'bellBtn\').addEventListener(\'click\', () => $(\'bellPanel\').classList.toggle(\'hidden\'));\n\n$(\'chatForm\').addEventListener(\'submit\', (e) => {\n  e.preventDefault();\n  const input = $(\'chatInput\');\n  const prompt = input.value.trim();\n  if (!prompt) return;\n  input.value = \'\';\n  sendChat(prompt);\n});\n\nrefresh();\nsetInterval(refresh, 5000);\n'

def info(msg):
    print(f"[Feature 002B Living Bridge] {msg}")

def write_text(rel, content):
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

def copy_item(src_rel):
    src = ROOT / src_rel
    if not src.exists():
        return
    dst = BACKUP_DIR / src_rel
    dst.parent.mkdir(parents=True, exist_ok=True)
    if src.is_dir():
        shutil.copytree(src, dst, dirs_exist_ok=True)
    else:
        shutil.copy2(src, dst)

def backup_project():
    info("Creating safety backup...")
    BACKUP_DIR.mkdir(parents=True, exist_ok=True)
    for item in ["Bridge","manifest.yaml","Forge","Foundry","Docs","00_START_HERE"]:
        copy_item(item)
    info(f"Backup created: {BACKUP_DIR}")

def install_polish():
    write_text("Bridge/index.html", INDEX_HTML)
    write_text("Bridge/style.css", STYLE_CSS)
    write_text("Bridge/renderer.js", RENDERER_JS)
    info("Bridge UI polished with boot screen, Workshop Bell, and capability cards.")

def update_manifest():
    path = ROOT / "manifest.yaml"
    text = path.read_text(encoding="utf-8", errors="replace") if path.exists() else ""
    if text and "feature_002b_living_bridge_polish: enabled" not in text:
        text += "\n  feature_002b_living_bridge_polish: enabled\n" if "features:" in text else "\nfeatures:\n  feature_002b_living_bridge_polish: enabled\n"
        path.write_text(text, encoding="utf-8")

def create_docs():
    write_text("Docs/FEATURE_002B_LIVING_BRIDGE_POLISH.md", """# Feature 002B - Living Bridge Polish

This patch upgrades the Bridge experience.

## Adds

- Startup boot screen
- Workshop Bell notifications
- Dynamic FOXAI capability cards
- Mission card
- Better professor grid
- Better live status indicators

## Run

```bat
Start_KayocktheOS.bat
Start_Bridge.bat
```
""")
    write_text("Forge/Decisions/0019_living_bridge_polish.md", """# Decision 0019 - Living Bridge Polish

The Bridge should feel like a living workshop, not an admin console.

The Home room should teach, assist, and build.
""")
    write_text("Foundry/Releases/feature002b_living_bridge_polish_notes.md", "# Feature 002B - Living Bridge Polish\n\nAdds startup sequence, capability cards, and Workshop Bell.\n")

def update_changelog():
    path = ROOT / "00_START_HERE/CHANGELOG.md"
    old = path.read_text(encoding="utf-8", errors="replace") if path.exists() else ""
    block = "\n\n## Feature 002B - Living Bridge Polish\n\n- Added Bridge boot screen.\n- Added Workshop Bell notifications.\n- Added dynamic capability cards.\n- Improved Home mission panel and Academy professor cards.\n"
    if "Feature 002B - Living Bridge Polish" not in old:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(old.rstrip() + block, encoding="utf-8")

def main():
    info(f"Project root: {ROOT}")
    backup_project()
    install_polish()
    update_manifest()
    create_docs()
    update_changelog()
    info("Feature 002B Living Bridge Polish complete.")
    info("Restart Start_Bridge.bat to see the update.")

if __name__ == "__main__":
    main()
